import { Elem } from "../Simple/Elem";

export const Maps = ({ item }) => {
  const coordsCsv = item.coordinates.join(",");
  const closeCoordsCsv = item.closest
    ? item.closest.coords
      ? item.closest.coords.join(",")
      : ""
    : "";
  const elems = [
    <MapGoogle key="1" coordsCsv={coordsCsv} closeCoordsCsv={closeCoordsCsv} />,
    <MapSatellite key="2" coordsCsv={coordsCsv} closeCoordsCsv={closeCoordsCsv} />,
    <MapEarth key="3" coordsCsv={coordsCsv} />,
    <MapStreetView key="4" coordsCsv={coordsCsv} />,
    <MapStandards key="5" coords={item.coordinates} />,
    <MapCrime key="6" coords={item.coordinates} />,
    <MapFlood key="7" coords={item.coordinates} />,
    <MapElevation key="8" coords={item.coordinates} />,
    <MapCycling key="9" coords={item.coordinates} />,
  ];
  return (
    <p>
      <strong>Maps:</strong> {elems.reduce((prev, curr) => [prev, " ◆ ", curr])}
    </p>
  );
};

const MapGoogle = ({ coordsCsv, closeCoordsCsv }) => {
  const url = closeCoordsCsv
    ? `https://www.google.com/maps/dir/${closeCoordsCsv}/${coordsCsv}/@15z/data=!4m2!4m1!3e2`
    : `https://www.google.com/maps/place/${coordsCsv}/@15z/data=!5m1!1e2`;
  const icon = <i className="fa-solid fa-map-location" style={{ color: "#b01010" }}></i>;
  return <Elem icon={icon} url={url} text="Map" />;
};

const MapSatellite = ({ coordsCsv, closeCoordsCsv }) => {
  const url = closeCoordsCsv
    ? `https://www.google.com/maps/dir/${closeCoordsCsv}/${coordsCsv}/@2696m/data=!3m1!1e3!4m2!4m1!3e2`
    : `https://www.google.com/maps/place/${coordsCsv}/@2696m/data=!3m1!1e3!5m1!1e2`;
  return <Elem icon="🛰" url={url} text="Satellite" />;
};

const MapEarth = ({ coordsCsv }) => {
  const url = `https://earth.google.com/web/@${coordsCsv},132a,25d,35y,0h,0t,0r`;
  return <Elem icon="🌍" url={url} text="Earth" />;
};

const MapStreetView = ({ coordsCsv }) => {
  const url = `https://www.google.com/maps/@${coordsCsv},3a,90y,70t/data=!3m1!1e1`;
  const icon = <i className="fa-solid fa-street-view" style={{ color: "#b08800" }}></i>;
  return <Elem icon={icon} url={url} text="StreetView" />;
};

const MapStandards = ({ coords }) => {
  const coordsJoined = coords.toReversed().join("*");
  const url = `https://open.xploria.co.uk/app/know-your-place?map=${coordsJoined}*18&view=elcAu7IT4`;
  return <Elem icon="💰" url={url} text="Standards" />;
};

const MapCrime = ({ coords }) => {
  const coordsJoined = coords.toReversed().join("*");
  const url = `https://open.xploria.co.uk/app/know-your-place?map=${coordsJoined}*18&view=elcAu7IT4&theme=w0fDyvnN_`;
  const icon = <i className="fa-solid fa-handcuffs" style={{ color: "#808080" }}></i>;
  return <Elem icon={icon} url={url} text="Crime" />;
};

const MapFlood = ({ coords }) => {
  const coordsJoined = coords.join("/");
  const url = `https://parallel.co.uk/rofrs/#16/${coordsJoined}`;
  return <Elem icon="🌊" url={url} text="Flood" />;
};

const MapElevation = ({ coords }) => {
  const coordsJoined = coords.join("%2C");
  const url = `https://en-gb.topographic-map.com/map/?center=${coordsJoined}&zoom=16&popup=${coordsJoined}`;
  const icon = <i className="fa-solid fa-mountain-sun" style={{ color: "#6fcdf9" }}></i>;
  return <Elem icon={icon} url={url} text="Elevation" />;
};

const MapCycling = ({ coords }) => {
  const coordsJoined = coords.join("/");
  const url = `https://www.cyclosm.org/#map=17/${coordsJoined}/cyclosm`;
  const icon = <i className="fa-solid fa-person-biking" style={{ color: "#b01010" }}></i>;
  return <Elem icon={icon} url={url} text="Cycling" />;
};

export default Maps;
