const BPagination = window.ReactBootstrap.Pagination;

const React = window.React;
const { useEffect } = React;

export const Pagination = ({
  items,
  setItemsDisplayed,
  activePage1,
  setActivePage1,
  PAGE_LENGTH,
}) => {
  const numPages = Math.ceil(items.length / PAGE_LENGTH);

  const onClick = (event) => {
    const btn = event.target.closest("a.page-link");
    if (!btn) return;
    let newPage1;
    if (btn.innerText.includes("First")) {
      newPage1 = 1;
    } else if (btn.innerText.includes("Previous")) {
      newPage1 = Math.max(1, activePage1 - 1);
    } else if (btn.innerText.includes("Next")) {
      newPage1 = Math.min(numPages, activePage1 + 1);
    } else if (btn.innerText.includes("Last")) {
      newPage1 = numPages;
    } else {
      newPage1 = parseInt(btn.innerText);
    }
    console.log(`Page change from: ${activePage1} to: ${newPage1}`);

    setActivePage1(newPage1);
    document.querySelector("#x-cards-container").scrollIntoView();
  };

  // Set displayed items
  useEffect(() => {
    const itemsDisplayed = [];
    for (let index = 0; index < items.length; ++index) {
      if (Math.floor(index / PAGE_LENGTH) + 1 === activePage1) {
        const item = items[index];
        item.loopIndex = `${index + 1} / ${items.length}`;
        itemsDisplayed.push(item);
        if (itemsDisplayed.length === PAGE_LENGTH) break;
      }
    }
    setItemsDisplayed(itemsDisplayed);
    console.log("itemsDisplayed", itemsDisplayed.length);
  }, [activePage1, items, setItemsDisplayed, PAGE_LENGTH]);

  // const pageButtons = (
  //   <>
  //     {activePage1 > 1 && <BPagination.Item>{1}</BPagination.Item>}
  //     {activePage1 > 2 && <BPagination.Ellipsis disabled />}
  //     <BPagination.Item active>{activePage1}</BPagination.Item>
  //     {activePage1 < numPages - 1 && <BPagination.Ellipsis disabled />}
  //     {activePage1 < numPages && <BPagination.Item>{numPages}</BPagination.Item>}
  //   </>
  // );
  const pageButtons = [...Array(numPages).keys()].map((index) => {
    return <BPagination.Item active={index + 1 === activePage1}>{index + 1}</BPagination.Item>;
  });

  return (
    <BPagination
      style={{ display: "flex", justifyContent: "center", flexWrap: "wrap", marginTop: "1rem" }}
      onClick={onClick}
    >
      <BPagination.Prev style={{ width: "4rem" }} />
      {pageButtons}
      <BPagination.Next style={{ width: "4rem" }} />
    </BPagination>
  );
};

export default Pagination;
